mapper.select:
SELECT * FROM product
AND id = #{id}
AND delete_time IS NULL

SELECT p.*
FROM `product` p

    p.delete_time IS NULL


        AND p.shop_id = #{param.shopId}


        AND p.id = #{param.searchId}


        AND p.id IN

            #{item}



        AND p.product_no LIKE CONCAT('%', #{param.productNo}, '%')


        AND p.name LIKE CONCAT('%', #{param.name}, '%')


        AND p.stock > 0


        AND p.stock = 0



        AND EXISTS (
        SELECT 1 FROM product_category_relation pcr
        WHERE pcr.product_id = p.id AND pcr.category_id = #{param.categoryId}
        )


        AND p.`status` IN

            #{item}



        AND p.status = #{param.status}


        AND p.is_virtual = #{param.isVirtual}


        AND p.scheduled_time <= #{param.limitTime}


        AND p.create_time >= #{param.startTime}


        AND p.create_time <= #{param.endTime}

    AND delete_time IS NULL

ORDER BY p.sort DESC, p.id DESC

mapper.update:
UPDATE `product`
SET `stock` = `stock` + #{stock}
WHERE `id` = #{id} AND delete_time IS NULL

UPDATE product
SET status = #{status}
WHERE id IN

    #{item}

AND delete_time is null
